// Read a value from the cache by its key.
export function cacheGet(key: string) {
  return key;
}

// Write a value into the cache under the given key.
export function cacheSet(key: string, val: string) {
  return val;
}

// Evict a stale entry from the cache to free memory.
export function evictEntry(key: string) {
  return key;
}
